pub fn setext_heading_line(s: &[u8]) -> Option<SetextChar> {
    let mut cursor = 0;
    let mut marker = 0;
    let len = s.len();

    {
        #[allow(unused_assignments)]
        let mut yych: u8 = 0;
        let mut yystate: usize = 0;
        'yyl: loop {
            match yystate {
                0 => {
                    yych = unsafe {
                        if cursor < len {
                            *s.get_unchecked(cursor)
                        } else {
                            0
                        }
                    };
                    cursor += 1;
                    match yych {
                        0x2D => {
                            yystate = 3;
                            continue 'yyl;
                        }
                        0x3D => {
                            yystate = 4;
                            continue 'yyl;
                        }
                        _ => {
                            yystate = 1;
                            continue 'yyl;
                        }
                    }
                }
                1 => {
                    yystate = 2;
                    continue 'yyl;
                }
                2 => {
                    return None;
                }
                3 => {
                    marker = cursor;
                    yych = unsafe {
                        if cursor < len {
                            *s.get_unchecked(cursor)
                        } else {
                            0
                        }
                    };
                    match yych {
                        0x09..=0x0A | 0x0D | 0x20 => {
                            yystate = 6;
                            continue 'yyl;
                        }
                        0x2D => {
                            cursor += 1;
                            yystate = 9;
                            continue 'yyl;
                        }
                        _ => {
                            yystate = 2;
                            continue 'yyl;
                        }
                    }
                }
                4 => {
                    marker = cursor;
                    yych = unsafe {
                        if cursor < len {
                            *s.get_unchecked(cursor)
                        } else {
                            0
                        }
                    };
                    match yych {
                        0x09..=0x0A | 0x0D | 0x20 => {
                            yystate = 11;
                            continue 'yyl;
                        }
                        0x3D => {
                            cursor += 1;
                            yystate = 13;
                            continue 'yyl;
                        }
                        _ => {
                            yystate = 2;
                            continue 'yyl;
                        }
                    }
                }
                5 => {
                    yych = unsafe {
                        if cursor < len {
                            *s.get_unchecked(cursor)
                        } else {
                            0
                        }
                    };
                    yystate = 6;
                    continue 'yyl;
                }
                6 => match yych {
                    0x09 | 0x20 => {
                        cursor += 1;
                        yystate = 5;
                        continue 'yyl;
                    }
                    0x0A | 0x0D => {
                        cursor += 1;
                        yystate = 8;
                        continue 'yyl;
                    }
                    _ => {
                        yystate = 7;
                        continue 'yyl;
                    }
                },
                7 => {
                    cursor = marker;
                    yystate = 2;
                    continue 'yyl;
                }
                8 => {
                    return Some(SetextChar::Hyphen);
                }
                9 => {
                    yych = unsafe {
                        if cursor < len {
                            *s.get_unchecked(cursor)
                        } else {
                            0
                        }
                    };
                    match yych {
                        0x09 | 0x20 => {
                            cursor += 1;
                            yystate = 5;
                            continue 'yyl;
                        }
                        0x0A | 0x0D => {
                            cursor += 1;
                            yystate = 8;
                            continue 'yyl;
                        }
                        0x2D => {
                            cursor += 1;
                            yystate = 9;
                            continue 'yyl;
                        }
                        _ => {
                            yystate = 7;
                            continue 'yyl;
                        }
                    }
                }
                10 => {
                    yych = unsafe {
                        if cursor < len {
                            *s.get_unchecked(cursor)
                        } else {
                            0
                        }
                    };
                    yystate = 11;
                    continue 'yyl;
                }
                11 => match yych {
                    0x09 | 0x20 => {
                        cursor += 1;
                        yystate = 10;
                        continue 'yyl;
                    }
                    0x0A | 0x0D => {
                        cursor += 1;
                        yystate = 12;
                        continue 'yyl;
                    }
                    _ => {
                        yystate = 7;
                        continue 'yyl;
                    }
                },
                12 => {
                    return Some(SetextChar::Equals);
                }
                13 => {
                    yych = unsafe {
                        if cursor < len {
                            *s.get_unchecked(cursor)
                        } else {
                            0
                        }
                    };
                    match yych {
                        0x09 | 0x20 => {
                            cursor += 1;
                            yystate = 10;
                            continue 'yyl;
                        }
                        0x0A | 0x0D => {
                            cursor += 1;
                            yystate = 12;
                            continue 'yyl;
                        }
                        0x3D => {
                            cursor += 1;
                            yystate = 13;
                            continue 'yyl;
                        }
                        _ => {
                            yystate = 7;
                            continue 'yyl;
                        }
                    }
                }
                _ => {
                    panic!("internal lexer error")
                }
            }
        }
    }
}

pub fn set_y(&mut self, x: f32) {
    let x_le = x.to_little_endian();
    // Safety:
    // Created from a valid Table for this object
    // Which contains a valid value in this slot
    unsafe {
      core::ptr::copy_nonoverlapping(
        &x_le as *const _ as *const u8,
        self.0[4..].as_mut_ptr(),
        core::mem::size_of::<<f32 as EndianScalar>::Scalar>(),
      );
    }
  }

pub fn cell_output(&self) -> CellOutputOptReader<'r> {
        let offsets = self.field_offsets();
        let start = molecule::unpack_number(&offsets[2][..]) as usize;
        if self.has_extra_fields() {
            let end = molecule::unpack_number(&offsets[3][..]) as usize;
            CellOutputOptReader::new_unchecked(&self.as_slice()[start..end])
        } else {
            CellOutputOptReader::new_unchecked(&self.as_slice()[start..])
        }
    }

fn quote_iunknown_impl(&self) -> TokenStream {
        let name = self.name;
        let refcount = self.refc_member;
        let (impgen, tygen, wherec) = self.generics.split_for_impl();

        let is_equal_iid = self.interfaces.iter().map(|path| {
            quote! {
                winapi::shared::guiddef::IsEqualIID(
                    &*riid,
                    &<#path as winapi::Interface>::uuidof(),
                )
            }
        });

        quote! {
            #[allow(non_snake_case)]
            impl #impgen #name #tygen #wherec {
                #[inline(never)]
                unsafe extern "system" fn __com_impl__IUnknown__AddRef(
                    this: *mut winapi::um::unknwnbase::IUnknown,
                ) -> u32 {
                    let this = &*(this as *const Self);
                    this.#refcount.add_ref()
                }

                #[inline(never)]
                unsafe extern "system" fn __com_impl__IUnknown__Release(
                    this: *mut winapi::um::unknwnbase::IUnknown,
                ) -> u32 {
                    let ptr = this as *mut Self;
                    let count = (*ptr).#refcount.release();
                    if count == 0 {
                        // This was the last ref
                        Box::from_raw(ptr);
                    }
                    count
                }

                #[inline(never)]
                unsafe extern "system" fn __com_impl__IUnknown__QueryInterface(
                    this: *mut winapi::um::unknwnbase::IUnknown,
                    riid: *const winapi::shared::guiddef::IID,
                    ppv: *mut *mut winapi::ctypes::c_void,
                ) -> winapi::shared::winerror::HRESULT {
                    if ppv.is_null() {
                        return winapi::shared::winerror::E_POINTER;
                    }
                    if #( #is_equal_iid )||* {
                        *ppv = this as *mut winapi::ctypes::c_void;
                        winapi::shared::winerror::S_OK
                    } else {
                        *ppv = std::ptr::null_mut();
                        winapi::shared::winerror::E_NOINTERFACE
                    }
                }
            }
        }
    }

pub fn retire_dcid(&mut self, seq: u64) -> Result<Option<usize>> {
        if self.zero_length_dcid {
            return Err(Error::InvalidState);
        }

        let e = self.dcids.remove(seq)?.ok_or(Error::InvalidState)?;

        self.mark_retire_dcid_seq(seq, true)?;

        Ok(e.path_id)
    }

fn visit_byte_buf<E: de::Error>(self, value: Vec<u8>) -> DResult<E> {
        let (tag, mut bytes) = value.split_at(1);
        match tag[0] {
            0u8 => {
                let v = Int(num_bigint::BigInt::from_signed_bytes_le(bytes));
                Ok(IDLValue::Int(v))
            }
            1u8 => {
                let v = Nat(num_bigint::BigUint::from_bytes_le(bytes));
                Ok(IDLValue::Nat(v))
            }
            2u8 => {
                let v = crate::Principal::try_from(bytes).map_err(E::custom)?;
                Ok(IDLValue::Principal(v))
            }
            4u8 => {
                let v = crate::Principal::try_from(bytes).map_err(E::custom)?;
                Ok(IDLValue::Service(v))
            }
            5u8 => {
                use std::io::Read;
                let len = leb128::read::unsigned(&mut bytes).map_err(E::custom)? as usize;
                let mut buf = vec![0; len];
                bytes.read_exact(&mut buf).map_err(E::custom)?;
                let meth = String::from_utf8(buf).map_err(E::custom)?;
                let id = crate::Principal::try_from(bytes).map_err(E::custom)?;
                Ok(IDLValue::Func(id, meth))
            }
            3u8 => Ok(IDLValue::Reserved),
            _ => Err(de::Error::custom("unknown tag in visit_byte_buf")),
        }
    }

fn get_array_ref<T: ByteValued>(
        &self,
        offset: usize,
        n: usize,
    ) -> Result<VolatileArrayRef<T, BS<Self::B>>> {
        // Use isize to avoid problems with ptr::offset and ptr::add down the line.
        let nbytes = isize::try_from(n)
            .ok()
            .and_then(|n| n.checked_mul(size_of::<T>() as isize))
            .ok_or(Error::TooBig {
                nelements: n,
                size: size_of::<T>(),
            })?;
        let slice = self.get_slice(offset, nbytes as usize)?;
        // SAFETY: This is safe because the pointer is range-checked by get_slice, and
        // the lifetime is the same as self.
        unsafe {
            Ok(VolatileArrayRef::with_bitmap(
                slice.addr,
                n,
                slice.bitmap,
                slice.mmap,
            ))
        }
    }

