pub unsafe fn extend_from_within_unchecked(&mut self, start: usize, len: usize) {
        if self.head < self.tail {
            // continous data slice  |____HDDDDDDDT_____|
            let after_tail = usize::min(len, self.cap - self.tail);
            unsafe {
                let src = (
                    self.buf.as_ptr().cast_const().add(self.head + start),
                    self.tail - self.head,
                );
                let dst = (self.buf.as_ptr().add(self.tail), self.cap - self.tail);
                copy_bytes_overshooting(src, dst, after_tail);

                if after_tail < len {
                    let src = (src.0.add(after_tail), src.1 - after_tail);
                    let dst = (self.buf.as_ptr(), self.head);
                    copy_bytes_overshooting(src, dst, len - after_tail);
                }
            }
        } else {
            // continous free slice |DDDT_________HDDDD|
            if self.head + start > self.cap {
                let start = (self.head + start) % self.cap;
                unsafe {
                    let src = (
                        self.buf.as_ptr().add(start).cast_const(),
                        self.cap - self.head,
                    );
                    let dst = (self.buf.as_ptr().add(self.tail), self.head - self.tail);
                    copy_bytes_overshooting(src, dst, len);
                }
            } else {
                let after_start = usize::min(len, self.cap - self.head - start);
                unsafe {
                    let src = (
                        self.buf.as_ptr().add(self.head + start).cast_const(),
                        self.cap - self.head,
                    );
                    let dst = (self.buf.as_ptr().add(self.tail), self.head - self.tail);
                    copy_bytes_overshooting(src, dst, after_start);

                    if after_start < len {
                        let src = (self.buf.as_ptr().cast_const(), self.tail);
                        let dst = (dst.0.add(after_start), dst.1 - after_start);
                        copy_bytes_overshooting(src, dst, len - after_start);
                    }
                }
            }
        }

        self.tail = (self.tail + len) % self.cap;
    }

fn email_match<'a>(
    arena: &'a Arena<AstNode<'a>>,
    contents: &[u8],
    i: usize,
) -> Option<(&'a AstNode<'a>, usize, usize)> {
    static EMAIL_OK_SET: Lazy<[bool; 256]> = Lazy::new(|| {
        let mut sc = [false; 256];
        for c in &[b'.', b'+', b'-', b'_'] {
            sc[*c as usize] = true;
        }
        sc
    });

    let size = contents.len();

    let mut rewind = 0;

    while rewind < i {
        let c = contents[i - rewind - 1];

        if isalnum(c) || EMAIL_OK_SET[c as usize] {
            rewind += 1;
            continue;
        }

        break;
    }

    if rewind == 0 {
        return None;
    }

    let mut link_end = 1;
    let mut np = 0;

    while link_end < size - i {
        let c = contents[i + link_end];

        if isalnum(c) {
            // empty
        } else if c == b'@' {
            return None;
        } else if c == b'.' && link_end < size - i - 1 && isalnum(contents[i + link_end + 1]) {
            np += 1;
        } else if c != b'-' && c != b'_' {
            break;
        }

        link_end += 1;
    }

    if link_end < 2
        || np == 0
        || (!isalpha(contents[i + link_end - 1]) && contents[i + link_end - 1] != b'.')
    {
        return None;
    }

    link_end = autolink_delim(&contents[i..], link_end);
    if link_end == 0 {
        return None;
    }

    let mut url = "mailto:".to_string();
    let text = str::from_utf8(&contents[i - rewind..link_end + i]).unwrap();
    url.push_str(text);

    let inl = make_inline(
        arena,
        NodeValue::Link(NodeLink {
            url,
            title: String::new(),
        }),
    );

    inl.append(make_inline(arena, NodeValue::Text(text.to_string())));
    Some((inl, rewind, rewind + link_end))
}

pub fn reset(&mut self, total_bytes: u64, gen_type: PassType<'a>) {
        if let PassType::Random = gen_type {
            if self.rng.is_none() {
                self.rng = Some(RefCell::new(rand::thread_rng()));
            }
        }

        self.total_bytes = total_bytes;
        self.gen_type = gen_type;

        self.bytes_generated.set(0);
    }

