pub async fn init(
	StartCommandArguments {
		path,
		username: user,
		password: pass,
		enable_auth_level,
		client_ip,
		listen_addresses,
		dbs,
		web,
		log,
		tick_interval,
		no_banner,
		..
	}: StartCommandArguments,
) -> Result<(), Error> {
	// Initialize opentelemetry and logging
	crate::telemetry::builder().with_filter(log).init();
	// Start metrics subsystem
	crate::telemetry::metrics::init(&TelemetryContext::current())
		.expect("failed to initialize metrics");

	// Check if a banner should be outputted
	if !no_banner {
		// Output SurrealDB logo
		println!("{LOGO}");
	}
	// Clean the path
	let endpoint = path.into_endpoint()?;
	let path = if endpoint.path.is_empty() {
		endpoint.url.to_string()
	} else {
		endpoint.path
	};
	// Setup the cli options
	let _ = config::CF.set(Config {
		bind: listen_addresses.first().cloned().unwrap(),
		client_ip,
		path,
		user,
		pass,
		enable_auth_level,
		tick_interval,
		crt: web.as_ref().and_then(|x| x.web_crt.clone()),
		key: web.as_ref().and_then(|x| x.web_key.clone()),
	});
	// This is the cancellation token propagated down to
	// all the async functions that needs to be stopped gracefully.
	let ct = CancellationToken::new();
	// Initiate environment
	env::init().await?;
	// Start the kvs server
	dbs::init(dbs).await?;
	// Start the node agent
	#[cfg(feature = "has-storage")]
	let nd = node::init(ct.clone());
	// Start the web server
	net::init(ct).await?;
	// Wait for the node agent to stop
	#[cfg(feature = "has-storage")]
	if let Err(e) = nd.await {
		error!("Node agent failed while running: {}", e);
		return Err(Error::NodeAgent);
	}
	// All ok
	Ok(())
}

pub unsafe fn sigstack_mut(&mut self) -> &mut [u8] {
        std::slice::from_raw_parts_mut(self.slot().sigstack as *mut u8, libc::SIGSTKSZ)
    }

pub fn bind(addr: io::Result<&SocketAddr>) -> io::Result<UdpSocket> {
        let addr = addr?;

        init();

        let sock = Socket::new(addr, c::SOCK_DGRAM)?;
        let (addrp, len) = addr.into_inner();
        cvt(unsafe { c::bind(sock.as_raw(), addrp, len as _) })?;
        Ok(UdpSocket { inner: sock })
    }

async fn backup_http_to_file<W: AsyncWrite + Unpin>(
	from: &str,
	mut into: W,
	auth: &AuthArguments,
	level: &LevelSelectionArguments,
) -> Result<(), Error> {
	let mut from = StreamReader::new(
		get_http_sync_body(from, auth, level)
			.await?
			.bytes_stream()
			.map_err(|x| std::io::Error::new(ErrorKind::Other, x)),
	);

	// Copy the data to the destination
	copy(&mut from, &mut into).await?;
	into.flush().await?;
	// Everything OK
	Ok(())
}

pub fn from_content<S: decode::Source>(
        content: &mut decode::Content<S>
    ) -> Result<Self, DecodeError<S::Error>> {
        match *content {
            decode::Content::Primitive(ref mut inner) => {
                if inner.mode() == Mode::Cer && inner.remaining() > 1000 {
                    return Err(content.content_err(
                        "long bit string component in CER mode"
                    ))
                }
                Ok(BitString {
                    unused: inner.take_u8()?,
                    bits: inner.take_all()?,
                })
            }
            decode::Content::Constructed(ref inner) => {
                if inner.mode() == Mode::Der {
                    Err(content.content_err(
                       "constructed bit string in DER mode"
                    ))
                }
                else {
                    Err(content.content_err(
                        "constructed bit string not implemented"
                    ))
                }
            }
        }
    }

pub fn do_secp256r1_verify<A: BackendApi + 'static, S: Storage + 'static, Q: Querier + 'static>(
    mut env: FunctionEnvMut<Environment<A, S, Q>>,
    hash_ptr: u32,
    signature_ptr: u32,
    pubkey_ptr: u32,
) -> VmResult<u32> {
    let (data, mut store) = env.data_and_store_mut();

    charge_host_call_gas(data, &mut store)?;

    let hash = read_region(data, &mut store, hash_ptr, MESSAGE_HASH_MAX_LEN)?;
    let signature = read_region(data, &mut store, signature_ptr, ECDSA_SIGNATURE_LEN)?;
    let pubkey = read_region(data, &mut store, pubkey_ptr, ECDSA_PUBKEY_MAX_LEN)?;

    let gas_info = GasInfo::with_cost(data.gas_config.secp256r1_verify_cost);
    process_gas_info(data, &mut store, gas_info)?;

    let result = secp256r1_verify(&hash, &signature, &pubkey);
    let code = match result {
        Ok(valid) => {
            if valid {
                SECP256R1_VERIFY_CODE_VALID
            } else {
                SECP256R1_VERIFY_CODE_INVALID
            }
        }
        Err(err) => match err {
            CryptoError::InvalidHashFormat { .. }
            | CryptoError::InvalidPubkeyFormat { .. }
            | CryptoError::InvalidSignatureFormat { .. }
            | CryptoError::GenericErr { .. } => err.code(),
            CryptoError::Aggregation { .. }
            | CryptoError::PairingEquality { .. }
            | CryptoError::BatchErr { .. }
            | CryptoError::InvalidPoint { .. }
            | CryptoError::InvalidRecoveryParam { .. }
            | CryptoError::UnknownHashFunction { .. } => {
                panic!("Error must not happen for this call")
            }
        },
    };
    Ok(code)
}

